const fs = require\('fs'\);
let total = 0, count = 0;
for\(let i = 1; i <= 5; i++\) {
  const text = fs.readFileSync\('lib/data-part' + i + '.ts', 'utf8'\);
  const matches = text.match\(/content: \\`\([\\s\\S]*?\)\\`,/g\) || [];
  matches.forEach\(\(m, j\) => {
    const content = m.replace\(/content: \\`/, ''\).replace\(/\\`,\\s*$/, ''\);
    const words = content.split\(/\\s+/\).length;
    console.log\('Part' + i + ' Topic' + \(j+1\) + ': ' + words + ' מילים'\);
    total += words; count++;
  }\);
}
console.log\('\\\\nממוצע:', Math.round\(total/count\), 'מילים לנושא'\);
")

